DELIMITER $$
--
-- Procédures
--
DROP PROCEDURE IF EXISTS `add_stock`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `add_stock` (IN `p_product_id` BIGINT, IN `p_variant_id` BIGINT, IN `p_quantity` INT)   BEGIN
    IF p_variant_id IS NOT NULL THEN
        UPDATE product_variants SET stock_qty = stock_qty + p_quantity WHERE id = p_variant_id;
    ELSE
        UPDATE products SET stock_qty = stock_qty + p_quantity WHERE id = p_product_id;
    END IF;
END$$

DROP PROCEDURE IF EXISTS `deduct_stock`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `deduct_stock` (IN `p_product_id` BIGINT, IN `p_variant_id` BIGINT, IN `p_quantity` INT, OUT `p_success` BOOLEAN, OUT `p_message` VARCHAR(255))   BEGIN
    DECLARE v_current_stock INT;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        ROLLBACK;
        SET p_success = FALSE;
        SET p_message = 'Erreur technique lors de la vérification du stock.';
    END;

    START TRANSACTION;

    IF p_variant_id IS NOT NULL THEN
        SELECT stock_qty INTO v_current_stock FROM product_variants WHERE id = p_variant_id FOR UPDATE;
        IF v_current_stock >= p_quantity THEN
            UPDATE product_variants SET stock_qty = stock_qty - p_quantity WHERE id = p_variant_id;
            SET p_success = TRUE;
            SET p_message = 'Stock variante déduit.';
        ELSE
            SET p_success = FALSE;
            SET p_message = CONCAT('Stock variante insuffisant. Reste: ', v_current_stock);
        END IF;
    ELSE
        SELECT stock_qty INTO v_current_stock FROM products WHERE id = p_product_id FOR UPDATE;
        IF v_current_stock >= p_quantity THEN
            UPDATE products SET stock_qty = stock_qty - p_quantity WHERE id = p_product_id;
            SET p_success = TRUE;
            SET p_message = 'Stock produit déduit.';
        ELSE
            SET p_success = FALSE;
            SET p_message = CONCAT('Stock produit insuffisant. Reste: ', v_current_stock);
        END IF;
    END IF;

    IF p_success = FALSE THEN ROLLBACK; ELSE COMMIT; END IF;
END$$

DROP PROCEDURE IF EXISTS `update_product_rating`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `update_product_rating` (IN `p_product_id` BIGINT)   BEGIN
    DECLARE v_new_avg DECIMAL(2,1);
    SELECT AVG(rating) INTO v_new_avg FROM reviews WHERE product_id = p_product_id AND is_verified = TRUE;
    IF v_new_avg IS NULL THEN SET v_new_avg = 0.0; END IF;
    UPDATE products SET rating_avg = v_new_avg WHERE id = p_product_id;
END$$

DELIMITER ;

