DROP TABLE IF EXISTS `products`;
CREATE TABLE IF NOT EXISTS `products` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `sku` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `brand` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category_id` bigint NOT NULL,
  `default_supplier_id` bigint DEFAULT NULL COMMENT 'Fournisseur principal',
  `base_price` decimal(38,2) NOT NULL,
  `discount_price` decimal(38,2) DEFAULT NULL,
  `cost_price` decimal(38,2) DEFAULT NULL,
  `stock_qty` int DEFAULT '0' COMMENT 'Stock global si PAS de variantes',
  `is_active` tinyint(1) DEFAULT '1',
  `rating_avg` double DEFAULT NULL,
  `views_count` int DEFAULT '0',
  `specifications` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'Ex: {"Ecran": "6.1", "Puce": "A16 Bionic"}',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`),
  UNIQUE KEY `slug` (`slug`),
  KEY `default_supplier_id` (`default_supplier_id`),
  KEY `idx_products_category` (`category_id`),
  KEY `idx_products_active` (`is_active`)
) ;

