  `status` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'EN_ATTENTE' COMMENT 'EN_ATTENTE, CONFIRMEE, EN_ROUTE, PARTIELLEMENT_RECEPTIONNEE, RECEPTIONNEE, ANNULEE',
