  `type` enum('RETOUR','GARANTIE','REMBOURSEMENT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'OUVERT' COMMENT 'OUVERT, EN_COURS, RESOLU, FERME',
